     1→import { Logger } from '@nestjs/common';
     2→import { Command, CommandRunner, Option } from 'nest-commander';
     3→
     4→import { StylesMvModel } from '@modules/db/styles-mv/models/styles-mv.model';
     5→import { EnvConfigService } from '@modules/env-config/env-config.service';
     6→import { OpensearchNeuralService } from '@modules/opensearch/opensearch-neural.service';
     7→import { OpensearchService } from '@modules/opensearch/opensearch.service';
     8→
     9→import { runWithConcurrencyLimit } from '@utils/concurrency-pool.util';
    10→import { ProgressBar } from '@utils/progress-bar.util';
    11→
    12→import { OPENSEARCH_INDEX_NAME } from '@constants/env-variables.constant';
    13→
    14→import { CronJobExecution } from '@decorators/cron-job-execution.decorator';
    15→
    16→interface ReindexProductsNeuralOptions {
    17→	batchSize?: number;
    18→	concurrency?: number;
    19→	createIndex?: boolean;
    20→	recreateIndex?: boolean;
    21→}
    22→
    23→@Command({
    24→	name: 'reindex-products-neural',
    25→	description: 'Sync styles_mv products to OpenSearch neural search index',
    26→})
    27→export class ReindexProductsNeuralCommand extends CommandRunner {
    28→	private readonly logger = new Logger(ReindexProductsNeuralCommand.name);
    29→	private isShuttingDown = false;
    30→	private currentOperation: Promise<void> | null = null;
    31→	private isCancelled = false;
    32→
    33→	constructor(
    34→		private readonly opensearchNeuralService: OpensearchNeuralService,
    35→		private readonly opensearchService: OpensearchService,
    36→		private readonly stylesMvModel: StylesMvModel,
    37→		private readonly configService: EnvConfigService,
    38→	) {
    39→		super();
    40→		this.setupGracefulShutdown();
    41→	}
    42→
    43→	@CronJobExecution({ jobName: 'reindex-products-neural' })
    44→	async run(
    45→		_passedParams: string[],
    46→		options: ReindexProductsNeuralOptions,
    47→	): Promise<void> {
    48→		if (this.isShuttingDown) {
    49→			this.logger.warn('Command cancelled due to shutdown signal');
    50→			return;
    51→		}
    52→
    53→		const batchSize = options.batchSize ?? 150;
    54→		const concurrency = options.concurrency ?? 5;
    55→		const createIndex = options.createIndex ?? false;
    56→		const recreateIndex = options.recreateIndex ?? false;
    57→
    58→		try {
    59→			const indexName = this.configService.get<string>({ key: OPENSEARCH_INDEX_NAME });
    60→
    61→			if (recreateIndex) {
    62→				this.logger.log(`Dropping OpenSearch index: ${indexName}`);
    63→				await this.opensearchService.deleteIndex({ indexName });
    64→				this.logger.log(`Creating OpenSearch index: ${indexName}`);
    65→				await this.opensearchNeuralService.createProductsIndex({ indexName });
    66→			} else if (createIndex) {
    67→				this.logger.log(`Creating OpenSearch index: ${indexName}`);
    68→				await this.opensearchNeuralService.createProductsIndex({ indexName });
    69→			}
    70→
    71→			this.logger.log('Starting to reindex products to OpenSearch');
    72→			this.logger.log(`Batch size: ${batchSize}, Concurrency: ${concurrency}`);
    73→
    74→			const totalCount = await this.stylesMvModel.count();
    75→			this.logger.log(`Total products to index: ${totalCount}`);
    76→
    77→			if (totalCount === 0) {
    78→				this.logger.warn('No products found to index');
    79→				return;
    80→			}
    81→
    82→			const totalBatches = Math.ceil(totalCount / batchSize);
    83→			const batches = Array.from({ length: totalBatches }, (_, i) => ({
    84→				offset: i * batchSize,
    85→				limit: batchSize,
    86→			}));
    87→
    88→			const progressBar = new ProgressBar({ total: totalCount });
    89→			let totalIndexed = 0;
    90→			let totalErrors = 0;
    91→
    92→			this.currentOperation = this.processBatches({
    93→				batches,
    94→				concurrency,
    95→				indexName,
    96→				progressBar,
    97→				onBatchComplete: (indexed, errors) => {
    98→					totalIndexed += indexed;
    99→					totalErrors += errors;
   100→				},
   101→			});
   102→
   103→			await this.currentOperation;
   104→
   105→			if (!this.isCancelled) {
   106→				progressBar.finish();
   107→				this.logger.log('Successfully completed reindexing products to OpenSearch');
   108→				this.logger.log(
   109→					`Total indexed: ${totalIndexed}, Total errors: ${totalErrors}, Total processed: ${totalIndexed + totalErrors}`,
   110→				);
   111→			} else {
   112→				this.logger.warn('Reindexing was cancelled');
   113→			}
   114→		} catch (error) {
   115→			// eslint-disable-next-line @typescript-eslint/no-unnecessary-condition
   116→			if (this.isShuttingDown || this.isCancelled) {
   117→				this.logger.warn('Command interrupted during shutdown');
   118→				return;
   119→			}
   120→			this.logger.error(`Failed to reindex products: ${(error as Error).message}`);
   121→			process.exit(1);
   122→		} finally {
   123→			this.currentOperation = null;
   124→		}
   125→	}
   126→
   127→	private async processBatches({
   128→		batches,
   129→		concurrency,
   130→		indexName,
   131→		progressBar,
   132→		onBatchComplete,
   133→	}: {
   134→		batches: { offset: number; limit: number }[];
   135→		concurrency: number;
   136→		indexName: string;
   137→		progressBar: ProgressBar;
   138→		onBatchComplete: (indexed: number, errors: number) => void;
   139→	}): Promise<void> {
   140→		await runWithConcurrencyLimit({
   141→			items: batches,
   142→			concurrency,
   143→			handler: async (batch) => {
