   214→	private setupGracefulShutdown(): void {
   215→		const signals: NodeJS.Signals[] = ['SIGTERM', 'SIGINT', 'SIGHUP', 'SIGQUIT'];
   216→
   217→		signals.forEach((signal) => {
   218→			process.on(signal, () => {
   219→				void this.handleShutdown(signal);
   220→			});
   221→		});
   222→
   223→		process.on('uncaughtException', (error) => {
   224→			this.logger.error(`Uncaught exception: ${error.message}`);
   225→			void this.handleShutdown('SIGTERM');
   226→		});
   227→
   228→		process.on('unhandledRejection', (reason) => {
   229→			this.logger.error(`Unhandled rejection: ${String(reason)}`);
   230→			void this.handleShutdown('SIGTERM');
   231→		});
   232→	}
   233→
   234→	private async handleShutdown(signal: string): Promise<void> {
   235→		if (this.isShuttingDown) {
   236→			this.logger.warn('Force shutdown requested, exiting immediately');
   237→			process.exit(1);
   238→		}
   239→
   240→		this.logger.warn(`Received ${signal} signal, initiating graceful shutdown...`);
   241→		this.isShuttingDown = true;
   242→		this.isCancelled = true;
   243→
   244→		try {
   245→			if (this.currentOperation) {
   246→				this.logger.log('Waiting for current operation to complete...');
   247→
   248→				const shutdownTimeout = setTimeout(() => {
   249→					this.logger.error('Graceful shutdown timeout, forcing exit');
   250→					process.exit(1);
   251→				}, 30000);
   252→
   253→				await this.currentOperation;
   254→				clearTimeout(shutdownTimeout);
   255→			}
   256→
   257→			this.logger.log('Graceful shutdown completed');
   258→			process.exit(0);
   259→		} catch (error) {
   260→			this.logger.error(`Error during shutdown: ${(error as Error).message}`);
   261→			process.exit(1);
   262→		}
   263→	}
   264→}
